import React,{useContext,useEffect,useState} from "react";
import { Link } from "react-router-dom";
import { Navbar } from "./Navbar";
import CartContext from "./context/CartContext";
import { useHistory } from "react-router";

export const OrderHistory = () => {
  const [Products, setProducts] = useState([]);
  const { historys } = useContext(CartContext);
  let history = useHistory();

  const url = "http://localhost:5000/api/product/getProducts";
  const getProducts = (variables) => {
    axios.post(url, variables).then((response) => {
      if (response.data.success) {
        setProducts(response.data.products);
        setPostSize(response.data.postSize);
        console.log(response.data.products);
      } else {
        alert("failed to fetch product data");
      }
    });
  };
  useEffect(() => {
    getProducts();
  }, [])
  return (
    <>
      <Navbar />
      <div className="container-fluid-history my-5 d-flex justify-content-center">
        <div className="card card-1">
          <div className="card-header bg-white">
            <div className="media flex-sm-row flex-column-reverse justify-content-between ">
              <div className="col my-auto">
                <h4 className="my-3" style={{ fontWeight: "normal" }}>
                  Your Order History
                </h4>
              </div>
            </div>
          </div>
          <div className="card-body">
            <div className="row justify-content-between mb-3">
              <div className="col-auto">
                <h6 className="color-1 mb-0 change-color">Orders</h6>
              </div>
              <div className="col-auto ">
                {" "}
                <small>Receipt Voucher : 1KAU9-84UIL</small>{" "}
              </div>
            </div>
            {
              historys.map((item)=>{
                return(
                <div className="row card-2 p-20">
              <div className="col-3 d-none d-lg-block">
                <div className="sq  ">
                  {" "}
                  <img
                    className="img-fluid my-auto  mr-2 mr-md-4 pl-0 p-0 m-0"
                    src={item.image}
                  />{" "}
                </div>
              </div>
              <div className="col-9">
                <div className="row justify-content-center">
                  <div className="row my-auto flex-column flex-md-row">
                    <div className="col my-auto text-center">
                      Item: {item.title}
                    </div>
                    <div className="col my-auto text-center"> Quantity : 1</div>
                    <div className="col my-auto"> Price: &#8377;3,600.00 </div>
                    <div className="col my-auto">Date : M</div>
                  </div>
                  <div className="mt-2 d-flex justify-content-center">
                    <Link to="#">
                      <button className="form-control btn btn-primary submit  ">
                        Buy Again
                      </button>
                    </Link>
                  </div>
                </div>
              </div>
            </div>)
              })
            }
          </div>
        </div>
      </div>
    </>
  );
};
